# --- 1. THE DUMMY WEB SERVER ---
class DummyHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        # This responds to Render's health checks
        self.send_response(200)
        self.send_header('Content-type', 'text/plain')
        self.end_headers()
        self.wfile.write(b"FORB1D Engine is Online.")

def run_dummy_server():
    # Render dynamically assigns a port, we must bind to it
    port = int(os.environ.get("PORT", 8080))
    server = HTTPServer(('0.0.0.0', port), DummyHandler)
    print(f"[SYSTEM] Dummy web server listening on port {port} to satisfy Render...")
    server.serve_forever()

# --- 2. THE FIREBASE LOGIC ---
def push_to_firebase(data_bytes):
    url = f"{FIREBASE_URL}?auth={AUTH_TOKEN}"
    req = urllib.request.Request(
        url, data=data_bytes, headers={'Content-Type': 'application/json'}, method='PATCH'
    )
    try:
        with urllib.request.urlopen(req) as response:
            return response.read().decode('utf-8')
    except Exception as e:
        return f"Error: {e}"

